const body = $json.body;

if (!body.photo) {
  throw new Error('No photo provided');
}

const photoBase64 = body.photo;

// Build data URL for GPT-4o Vision
const dataUrl = `data:image/jpeg;base64,${photoBase64}`;

return [{
  json: {
    dataUrl,
    userId: body.userId || null
  }
}];

